import{_ as i,o as a,c as e,a3 as o}from"./chunks/framework.LBeL10WQ.js";const u=JSON.parse('{"title":"Social Ads (publisher)","description":"Monetize your Instagram and TikTok audience via Partnership Ads. Complete guide to activating tagging, boost rights, and triggering your payment.","frontmatter":{"title":"Social Ads (publisher)","description":"Monetize your Instagram and TikTok audience via Partnership Ads. Complete guide to activating tagging, boost rights, and triggering your payment.","keywords":["social ads","partnership ads","instagram","tiktok","audience monetization","retail media"]},"headers":[],"relativePath":"en/publishers/sponsored-social/index.md","filePath":"en/publishers/sponsored-social/index.md"}'),s={name:"en/publishers/sponsored-social/index.md"};function r(n,t,d,l,c,p){return a(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="social-ads-partnership-ads" tabindex="-1">Social Ads (Partnership Ads) <a class="header-anchor" href="#social-ads-partnership-ads" aria-label="Permalink to &quot;Social Ads (Partnership Ads)&quot;">​</a></h1><p>Monetize your social audience (Instagram, TikTok) without polluting your editorial line through Partnership Ads.</p><hr><h2 id="the-concept" tabindex="-1">The concept <a class="header-anchor" href="#the-concept" aria-label="Permalink to &quot;The concept&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Unlike classic influencer marketing, we use <strong>Sponsorship</strong>:</p><ol><li>You create and publish quality content (with the &quot;Paid partnership&quot; label).</li><li>The advertiser invests their own media budget to broadcast <strong>your post</strong> to thousands of new people.</li><li>You share the publication link — getinside transmits it to the advertiser to launch the amplification.</li></ol></div><hr><h2 id="your-advantages" tabindex="-1">Your advantages <a class="header-anchor" href="#your-advantages" aria-label="Permalink to &quot;Your advantages&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>💰 Compensation</strong><p>You are paid for content creation and/or its publication. Revenue is credited to your Wallet 30 days after the campaign ends.</p></div><div class="gi-value-card"><strong>📈 Free Growth</strong><p>The advertiser pays to broadcast **your profile** to a large audience. Free subscriber acquisition without spending your own budget.</p></div><div class="gi-value-card"><strong>✨ Quality Preserved</strong><p>The post is amplified from your account (Dark post or Boost). No need to spam your organic feed.</p></div></div><hr><h2 id="why-use-getinside" tabindex="-1">Why use getinside? <a class="header-anchor" href="#why-use-getinside" aria-label="Permalink to &quot;Why use getinside?&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>⚙️ Simplified Setup</strong><p>Configuring advertising rights on Meta or TikTok is complex. We guide you step-by-step to activate permissions without errors.</p></div><div class="gi-value-card"><strong>🤝 Premium Brands</strong><p>Collaborate with verified advertisers who seek long-term performance, not one-off operations.</p></div></div><hr><h2 id="publishing-tagging-guide" tabindex="-1">Publishing &amp; Tagging Guide <a class="header-anchor" href="#publishing-tagging-guide" aria-label="Permalink to &quot;Publishing &amp; Tagging Guide&quot;">​</a></h2><p>For the advertiser to pay for the broadcast, you must imperatively activate the partnership options during publication.</p><div class="tip custom-block"><p class="custom-block-title">Why are these steps mandatory?</p><p>By checking &quot;Allow brand partner to boost&quot;, the advertiser can broadcast your content as an ad from their own account. Without this authorization, <strong>the campaign cannot start</strong> and <strong>your payment is blocked</strong>.</p></div><hr><h2 id="instagram-—-partnership-ads" tabindex="-1">Instagram — Partnership Ads <a class="header-anchor" href="#instagram-—-partnership-ads" aria-label="Permalink to &quot;Instagram — Partnership Ads&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Prepare the post</h3><p>Create your Post or Reel normally. Reach the final step (just before clicking &quot;Share&quot;).</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Advanced Settings</h3><p>Scroll to the very bottom and click on <strong>&quot;Advanced settings&quot;</strong>.</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Add the label + identify the brand</h3><p>Activate <strong>&quot;Add paid partnership label&quot;</strong>, then click on <strong>&quot;Add brand partners&quot;</strong> and search for the advertiser&#39;s account (indicated in the brief).</p></div></div><div class="gi-step"><div class="gi-step-num">4</div><div class="gi-step-body"><h3>Allow boost — Critical step</h3><p>Activate the <strong>&quot;Allow brand partner to boost&quot;</strong> option.</p></div></div><div class="danger custom-block"><p class="custom-block-title">Mandatory boost authorization (Instagram)</p><p>Without this box checked, the advertiser cannot launch the media campaign and your payment is blocked.</p><p>In case of a problem after publication: return to the post → 3 dots (…) → &quot;Edit&quot; → check the two options.</p></div><hr><h2 id="tiktok-—-spark-ads" tabindex="-1">TikTok — Spark Ads <a class="header-anchor" href="#tiktok-—-spark-ads" aria-label="Permalink to &quot;TikTok — Spark Ads&quot;">​</a></h2><div class="gi-step"><div class="gi-step-num">1</div><div class="gi-step-body"><h3>Access ad settings</h3><p>Publish the video. Go to it → click on the **3 dots (...)** in the bottom right → scroll to **&quot;Ad settings&quot;**.</p></div></div><div class="gi-step"><div class="gi-step-num">2</div><div class="gi-step-body"><h3>Activate authorization</h3><p>Toggle the **&quot;Ad authorization&quot;** option.</p></div></div><div class="gi-step"><div class="gi-step-num">3</div><div class="gi-step-body"><h3>Generate and send the code</h3><p>Click on **&quot;Generate code&quot;**, choose a duration (30 or 60 days), copy the code and paste it into the campaign messaging on <a href="https://app.getinside.media/" target="_blank">app.getinside.media</a>.</p></div></div><hr><h2 id="pre-publication-checklist" tabindex="-1">Pre-publication Checklist <a class="header-anchor" href="#pre-publication-checklist" aria-label="Permalink to &quot;Pre-publication Checklist&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Verify each point before publishing</p><ul><li><strong>Instagram:</strong> &quot;Paid partnership&quot; label enabled + advertiser account identified + <strong>&quot;Allow brand partner to boost&quot;</strong> checked</li><li><strong>TikTok:</strong> &quot;Ad authorization&quot; enabled + code generated and transmitted via platform messaging</li><li><strong>Both:</strong> After publication, confirm the broadcast on <a href="https://app.getinside.media/" target="_blank" rel="noreferrer">app.getinside.media</a> to trigger payment</li></ul></div><hr><h2 id="editorial-best-practices" tabindex="-1">Editorial Best Practices <a class="header-anchor" href="#editorial-best-practices" aria-label="Permalink to &quot;Editorial Best Practices&quot;">​</a></h2><div class="gi-value-grid"><div class="gi-value-card"><strong>🎯 Authenticity</strong><p>Use your usual tone. Don&#39;t play a role — that&#39;s exactly what the advertiser is looking for in you.</p></div><div class="gi-value-card"><strong>⚖️ Transparency</strong><p>The &quot;Paid partnership&quot; label is added automatically, ensuring your compliance with French advertising regulations.</p></div><div class="gi-value-card"><strong>📊 Performance</strong><p>Share the link of your publication with your getinside campaign manager for performance tracking and optimization.</p></div></div>',33)])])}const g=i(s,[["render",r]]);export{u as __pageData,g as default};
